// ─── Node.js Bot Template ───────────────────────────────────
// A simple bot skeleton that logs to stdout every 5 seconds.
// Replace the interval logic with your own bot framework
// (discord.js, telegraf, etc).

const BOT_NAME = process.env.BOT_NAME || 'MyBot';

console.log(`[${BOT_NAME}] Bot is starting...`);

let tick = 0;
const interval = setInterval(() => {
  tick++;
  console.log(`[${BOT_NAME}] Heartbeat #${tick} — ${new Date().toISOString()}`);
}, 5000);

// Graceful shutdown
process.on('SIGINT', () => {
  console.log(`[${BOT_NAME}] Received SIGINT. Shutting down...`);
  clearInterval(interval);
  process.exit(0);
});

process.on('SIGTERM', () => {
  console.log(`[${BOT_NAME}] Received SIGTERM. Shutting down...`);
  clearInterval(interval);
  process.exit(0);
});

console.log(`[${BOT_NAME}] Bot is online!`);
